2	import { nextGeneration, Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep block pattern unchanged (survival with 2-3 neighbors)", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    const sort = (cells: Cell[]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
18	    expect(sort(result)).toEqual(sort(block));
19	  });
20	  it("should transform blinker from horizontal to vertical (reproduction and underpopulation combined)", () => {
21	    const blinkerVertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
22	    const result = nextGeneration(blinkerVertical);
23	    const sort = (cells: Cell[]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
24	    expect(sort(result)).toEqual([[-1, 1], [0, 1], [1, 1]]);
25	  });
26	  it.todo("should kill center cell surrounded by more than 3 neighbors (overpopulation)");
27	});
